      super.connectedCallback();
    }
    render() {
      const open = `<${element} data-slot="${slot}" ${extraAttrs} class="${cn(classes)}">`;
      const close = `</${element}>`;
      return html`${unsafeHTML(open + this._slot + close)}`;
    }
  }
  Wrap.register(tag);
  return Wrap;
}

